#include<bits/stdc++.h>
using namespace std;
string s;
int c[7]= {0,2,3,5,7,11,13};
int a[7];
void cc(int q) {
	a[q+1]=a[q+1]+(a[q]/c[q]);
	a[q]=a[q]%c[q];
	return;
}
int main() {
	cin>>s;
	int n=s.size(),i=n-1,u=1;
	while(i>=0) {
		if(s[i]>='0'&&s[i]<='9') {
			if(s[i-1]>='0'&&s[i-1]<='9') {
				a[u]=a[u]+(s[i-1]-48)*10+(s[i]-48);
				i--;
			} else {
				a[u]=a[u]+s[i]-48;
			}
			u++;
		}
		if(s[i]=='+')u=1;
		i--;
	}
	for(int i=1; i<=5; i++)cc(i);
	int t=0;
	for(int i=6; i>=1; i--) {
		if(a[i]!=0) {
			t=i;
			break;
		}
	}
	for(int i=t; i>=2; i--) {
		cout<<a[i]<<",";
	}
	cout<<a[1];
	return 0;
}
